#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution
{
 public:
 int fairDistribution(vector<int> gifts)
 {
 int sum = 0;
 for (auto i : gifts)
 {
 sum += i;
 }
 int diff = 0;
 sort(gifts.begin(), gifts.end());
 int i = 0, j = gifts.size() - 1;
 while (i < j)
 {
 if (sum % 2 == 1)
 {
 diff += gifts[j];
 sum -= gifts[j];
 j--;
 }
 else
 {
 diff += gifts[i];
 sum -= gifts[i];
 i++;
 }
 }
 return abs(sum);
 }
};
